namespace SqrtTesting
{
    internal class Solver
    {
        public static double[] SolveEquation(double a, double b, double c)
        {
            double x1 = 0;
            double x2 = 0;


            if (a == 0)
            {
                x1 = -(c / b);
                return new double[] { Math.Round(x1, 3) };  
            }
            else
            {

                double D = b * b - 4 * a * c;
                D = Math.Round(D,3);

                if (D < 0)
                {
                    return new double[0];  

                }
                else if (D == 0)
                {
                    x1 = -b / (2 * a);
                    return new double[] { Math.Round(x1,3) };  
                }
                else
                {
                    x1 = (-b + Math.Sqrt(D)) / (2 * a);
                    x2 = (-b - Math.Sqrt(D)) / (2 * a);

                    return new double[] { Math.Round(x1, 3), Math.Round(x2, 3) }; 
                }

            }
        }
    }
}

