            Console.ReadKey();
        }

        static double Distance(double x1, double y1, double x2, double y2) /*Расстояние между точками*/
        {
            return Math.Sqrt(Math.Pow(x2 - x1, 2) + Math.Pow(y2 - y1, 2));
        }

        static double GetArea(double x1, double y1, double x2, double y2, double x3, double y3)
        {
            double аrea = 0.5 * Math.Abs((x2 - x1) * (y3 - y1) - (x3 - x1) * (y2 - y1));
            return аrea;
        }
        static double GetPerimeter(double x1, double y1, double x2, double y2, double x3, double y3)
        {
            double a = Distance(x1, y1, x2, y2);
            double b = Distance(x2, y2, x3, y3);
            double c = Distance(x3, y3, x1, y1);
            return a + b + c;
        }

        static double GetArea(double a, double b, double angle)
        {
            double angleRad = angle * Math.PI / 180;
            double area2 = 0.5 * a * b * Math.Sin(angleRad);
            return area2;
        }

        static double GetPerimeter(double a, double b, double c)
        {
            double perimeter2 = a + b+ c;
            return perimeter2;

        }
    }
