using System;

namespace TrigCalculator
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.Title = "Патласов Н.Д., Работа №3, Вариант 6";


            Console.WriteLine("Введите координаты трех вершин треугольника (x1 y1 x2 y2 x3 y3):");
            string input = Console.ReadLine();

            string[] coordinates = input.Split(' ');

            if (coordinates.Length != 6)
            {
                Console.WriteLine("Необходимо ввести 6 чисел через пробел! Ошибка!");
                return;
            }

            double x1, y1, x2, y2, x3, y3;
            if (!double.TryParse(coordinates[0], out x1) ||
                !double.TryParse(coordinates[1], out y1) ||
                !double.TryParse(coordinates[2], out x2) ||
                !double.TryParse(coordinates[3], out y2) ||
                !double.TryParse(coordinates[4], out x3) ||
                !double.TryParse(coordinates[5], out y3))
            {
                Console.WriteLine("Введены некорректные значения! Ошибка!");
                return;
            }


            if ((x1 == x2 && y1 == y2) || (x1 == x3 && y1 == y3) || (x2 == x3 && y2 == y3))
            {
                Console.WriteLine("Некоторые точки совпадают! Ошибка!");
                return;
            }


            if (IsCollinear(x1, y1, x2, y2, x3, y3))
            {
                Console.WriteLine("Точки лежат на одной прямой! Ошибка!");
                return;
            }

            double perimeter = GetPerimeter(x1, y1, x2, y2, x3, y3);
            double area = GetArea(x1, y1, x2, y2, x3, y3);

            double a = GetDistance(x1, y1, x2, y2);
            double b = GetDistance(x1, y1, x2, y2);
            double c = GetDistance(x1, y1, x2, y2);

            double perimeterSides = GetPerimeter(a, b, c);
            double areaSides = GetArea(a, b, c);


            Console.WriteLine("{0}: {1:F4}", "Периметр треугольника", perimeter);
            Console.WriteLine("{0}: {1:F4}", "Площадь треугольника", area);
            Console.WriteLine("{0}: {1:F4}", "Периметр треугольника(2 стороны)", perimeterSides);
            Console.WriteLine("{0}: {1:F4}", "Площадь треугольника(2 стороны)", areaSides);
        }


        static double GetDistance(double x1, double y1, double x2, double y2)
        {
            double distance = Math.Sqrt(Math.Pow(x2 - x1, 2) + Math.Pow(y2 - y1, 2));
            return distance;
        }


        static double GetPerimeter(double x1, double y1, double x2, double y2, double x3, double y3)
        {
            double a = GetDistance(x1, y1, x2, y2);
            double b = GetDistance(x2, y2, x3, y3);
            double c = GetDistance(x3, y3, x1, y1);

            double perimeter = a + b + c;
            return perimeter;
        }


        static double GetPerimeter(double a, double b, double c)
        {
            double perimeter = a + b + c;
            return perimeter;
        }


        static double GetArea(double x1, double y1, double x2, double y2, double x3, double y3)
        {
            double a = GetDistance(x1, y1, x2, y2);
            double b = GetDistance(x2, y2, x3, y3);
            double c = GetDistance(x3, y3, x1, y1);

            double p = (a + b + c) / 2;
            double area = Math.Sqrt(p * (p - a) * (p - b) * (p - c));
            return area;
        }


        static double GetArea(double a, double b, double c)
        {
            double p = (a + b + c) / 2;
            double area = Math.Sqrt(p * (p - a) * (p - b) * (p - c));
            return area;
        }


        static bool IsCollinear(double x1, double y1, double x2, double y2, double x3, double y3)
        {

            double area = Math.Abs((x2 - x1) * (y3 - y1) - (x3 - x1) * (y2 - y1)) / 2;
            return area < 0.0001;

        }

    }

}

internal class Program
    {
        static void Main(string[] args)
        {
            Console.Title = "Подкорытов Тихомир Алексеевич, работа № 2.2, квадратное уравнение";

            Console.WriteLine("Введите коэффиценты a, b и c через пробел:");
            string[] str = Console.ReadLine().Split();
            double a = double.Parse(str[0].Replace('.', ',')); 
            double b = double.Parse(str[1].Replace('.', ','));
            double c = double.Parse(str[2].Replace('.', ','));

            const double eps = 1e-9;

            if (a == 0)
            {
                Console.WriteLine("Уравнение не является квадратным");

                if (b != 0)
                {
                    double x = -c / b;
                    Console.WriteLine($"Корень уравнения: x = {x:f3}");
                }
                else
                {
                    if (c == 0)
                    {
                        Console.WriteLine("Бесконечно много решений");
                    }
                    else
                    {
                        Console.WriteLine("Нет решений");
                    }
                }
            }
            else
            {
                double D = b * b - 4 * a * c;

                if (D < -eps)
                {
                    Console.WriteLine("Нет корней");
                }
                else if (D < eps)
                {
                    double x = -b / (2 * a);

                    Console.WriteLine($"Корень уравнения: x = {x:f3}");
                }
                else
                {
                    double sqrtD = Math.Sqrt(D);

                    double x1 = (-b + sqrtD) / (2 * a);
                    double x2 = (-b - sqrtD) / (2 * a);

                    Console.WriteLine($"Корни x1 = {x1:f3}, x2 = {x2:f3}");
                }
            }

            Console.Write("Press any key to continue . . . ");
            Console.ReadKey();

