            }
            if (a == 0)
            {
                double x = (-c) / (b);
                return new double[] { Math.Round(x, 3) };
            }
            double j1 = (-b + Math.Sqrt(D)) / (2 * a);
            double j2 = (-b - Math.Sqrt(D)) / (2 * a);
