                if (a <= 0 || b <= 0 || angle <= 0 || angle >= 180)
                {
                    Console.WriteLine("Ошибка: неверные данные");
                    return;
                }

                double areaP = Area(a, b, angle);
                double perimeterP = Perimeter(a, b, angle);

                Console.WriteLine("Результаты:");
                Console.WriteLine("Периметр треугольника: {1:F4}", areaP, perimeterP);
