            static bool Check(double x1, double y1, double x2, double y2, double x3, double y3)
            {
                double a = Dist(x1, y1, x2, y2);
                double b = Dist(x2, y2, x3, y3);
                double c = Dist(x3, y3, x1, y1);

                return (a + b > c) && (a + c > b) && (b + c > a);
            }
            static double Dist(double x1, double y1, double x2, double y2)
            {
                return Math.Sqrt(Math.Pow(x2 - x1, 2) + Math.Pow(y2 - y1, 2));
            }
            static double Area(double x1, double y1, double x2, double y2, double x3, double y3)
            {
                double a = Dist(x1, y1, x2, y2);
                double b = Dist(x2, y2, x3, y3);
                double c = Dist(x3, y3, x1, y1);
                double p = (a + b + c) / 2;
                return Math.Sqrt(p * (p - a) * (p - b) * (p - c));
            }
            static double Perimeter(double x1, double y1, double x2, double y2, double x3, double y3)
            {
                double a = Dist(x1, y1, x2, y2);
                double b = Dist(x2, y2, x3, y3);
                double c = Dist(x3, y3, x1, y1);
                return a + b + c;
            }
            static double Area(double a, double b, double angle)
            {
                double angleR = angle * Math.PI / 180;
                return 0.5 * a * b * Math.Sin(angleR);
            }
            static double Perimeter(double a, double b, double angle)
            {
                double angleR = angle * Math.PI / 180;
                double c = Math.Sqrt(a * a + b * b - 2 * a * b * Math.Cos(angleR));
                return a + b + c;
            }
        }
    }

