namespace DistanceTest;
internal class Distance
{
    // Расстояние от точки P(px, py) до отрезка AB с координатами A(ax, ay), B(bx, by)
    public static double GetDistance(double px, double py, double ax, double ay, double bx, double by)
    {
        double abx = bx - ax; //длина отрезка AB
        double aby = by - ay;

        if (abx == 0 && aby == 0)
        {
            return Math.Sqrt((px - ax) * (px - ax) + (py - ay) * (py - ay)); // случай если отрезок AB это точка
        }
        double t = ((px - ax) * abx + (py - ay) * aby) / (abx * abx + aby * aby); //сколярное произведение векторов(P - A) и (B - A) / квадртат длины вектора AB
        //показывает, где находиться проекция точки Р на прямую АВ относительно отрезка
        // t = 0 - проекция в точке А
        // t = 1 - проекция в точке В
        // 0 < t < 1 - проекция между А и В


        if (t < 0) t = 0;
        if (t > 1) t = 1;

        double distanceX = ax + t * abx; //координата Х ближайшей точки на отрезке
        double distanceY = ay + t * aby; //координата Y ближайшей точки на отрезке

        return Math.Sqrt((px - distanceX) * (px - distanceX) + (py - distanceY) * (py - distanceY)); // вычесление расстояния между точкой P и ближайшей точкой на отрезке
    }
}

