namespace DistanceTest;
internal class Distance
{
    // Расстояние от точки P(px, py) до отрезка AB с координатами A(ax, ay), B(bx, by)
    public static double GetDistance(double px, double py, double ax, double ay, double bx, double by)
    {
        double distance;


        double segmentLengthSquared = Math.Pow(bx - ax, 2) + Math.Pow(by - ay, 2);


        if (segmentLengthSquared == 0)
        {
            distance = Math.Sqrt(Math.Pow(px - ax, 2) + Math.Pow(py - ay, 2));
            return distance;
        }

        double t = ((px - ax) * (bx - ax) + (py - ay) * (by - ay)) / segmentLengthSquared;


        if (t < 0)
        {
            distance = Math.Sqrt(Math.Pow(px - ax, 2) + Math.Pow(py - ay, 2));
        }
        else if (t > 1)
        {

            distance = Math.Sqrt(Math.Pow(px - bx, 2) + Math.Pow(py - by, 2));
        }
        else
        {

            double projectionX = ax + t * (bx - ax);
            double projectionY = ay + t * (by - ay);


            distance = Math.Sqrt(Math.Pow(px - projectionX, 2) + Math.Pow(py - projectionY, 2));
        }

        return distance;
    }
}

