        double Length = Math.Pow(x3 - x2, 2) + Math.Pow(y3 - y2, 2);//Вычисление квадрата длины отрезка между точками


        if (Length == 0)
        {
            distance = Math.Sqrt(Math.Pow(x1 - x2, 2) + Math.Pow(y1 - y2, 2));//Вычисление расстояния между точкой P и  A
            return distance;
        }

        double tt = ((x1 - x2) * (x3 - x2) + (y1 - y2) * (y3 - y2)) / Length;//Вычисление параметра проекции точки



        if (tt < 0)//Проверка, находится ли проекция за началом отрезка
        {
            distance = Math.Sqrt(Math.Pow(x1 - x2, 2) + Math.Pow(y1 - y2, 2));
        }
        else if (tt > 1)//Проверка, находится ли проекция за концом отрезка
        {

            distance = Math.Sqrt(Math.Pow(x1 - x3, 2) + Math.Pow(y1 - y3, 2));
        }
        else//Внутри отрезка
        {

            double XX = x2 + tt * (x3 - x2);//Вычисление координат проекции точки на отрезок
            double YY = y2 + tt * (y3 - y2);//Вычисление координат проекции точки на отрезок


            distance = Math.Sqrt(Math.Pow(x1 - XX, 2) + Math.Pow(y1 - YY, 2));//Вычисление расстояния до проекции на отрезке
        }

        return distance;
    }

}

