internal class Distance
{
    // Расстояние от точки P(px, py) до отрезка AB с координатами A(ax, ay), B(bx, by)
    public static double GetDistance(double px, double py, double ax, double ay, double bx, double by)
    {
        // Вектор AB
        double abx = bx - ax;
        double aby = by - ay;

        // Вектор AP
        double apx = px - ax;
        double apy = py - ay;

        // Вектор BP
        double bpx = px - bx;
        double bpy = py - by;

        double dotProduct = apx * abx + apy * aby;

        double abLengthSquared = abx * abx + aby * aby;

        // Если отрезок вырожден (точки A и B совпадают)
        if (abLengthSquared == 0)
        {
            return Math.Sqrt(apx * apx + apy * apy);
        }

        double t = dotProduct / abLengthSquared;

        // Проекция точки P на прямую AB находится за пределами отрезка AB
        if (t < 0.0)
        {
            // Ближайшая точка — A
            return Math.Sqrt(apx * apx + apy * apy);
        }
        else if (t > 1.0)
        {
            // Ближайшая точка — B
            return Math.Sqrt(bpx * bpx + bpy * bpy);
        }
        else
        {
            // Проекция лежит на отрезке AB
            double closestX = ax + t * abx;
            double closestY = ay + t * aby;

            // Расстояние от P до проекции
            double dx = px - closestX;
            double dy = py - closestY;
            return Math.Sqrt(dx * dx + dy * dy);
        }
    }
}

