                // Расчет характеристик

                double maxY = yValues.Max();
                double minY = yValues.Min();
                double avgY = yValues.Average();
                double stdDev = CalculateStandardDeviation(yValues, avgY);

                // Находим x для max и min

                double xForMax = startX + (yValues.IndexOf(maxY) * dX);
                double xForMin = startX + (yValues.IndexOf(minY) * dX);

                Console.WriteLine($"Наибольшее y = {maxY:F5} при x = {xForMax:F3}");
                Console.WriteLine($"Наименьшее y = {minY:F5} при x = {xForMin:F3}");
                Console.WriteLine($"Среднее = {avgY:F4}");
                Console.WriteLine($"Стандартное отклонение = {stdDev:F5}");

                Console.WriteLine(new string('-', 60));
                Console.WriteLine("Для повтора нажмите Enter, для выхода — любую другую клавишу...");
                BuildGraph.Start();
                continueKey = Console.ReadKey().Key.ToString();

            } while (continueKey == "Enter");

            Console.WriteLine("\nПрограмма завершена.");
            Console.ReadKey();
        }

        // Метод вычисления функции y = 1 - (1/4)*sin^2(2x) + cos(2x)

        static double CalculateY(double x)
        {
            return BuildGraph.GetFormula(x);
        }

        // Метод расчета стандартного отклонения

        static double CalculateStandardDeviation(List<double> values, double mean)
        {
            double sumOfSquares = 0;
            foreach (double val in values)
            {
                sumOfSquares += Math.Pow(val - mean, 2);
            }
            return Math.Sqrt(sumOfSquares / values.Count);
        }
    }
}

