namespace Чётвертая_работа
{
    internal class FileName()
    {
        public static double[] Calc(double[] x, double[] y, int NumOfSteps )
        {
            double sum = 0;
            double almost = 0;
            int[] i = { 0,0};

            double almalm = 0;
            double miny = y.Min();
            double maxy = y.Max();


            while (i[0] < NumOfSteps)
            {

                sum += y[i[0]];

                i[0] ++;
            }

                almost = sum / NumOfSteps;

                while(i[1] < NumOfSteps)
                {
                almalm += Math.Pow((y[i[1]] - almost),2);
                i[1] ++;
                }
                double MidRange = Math.Sqrt(almalm / NumOfSteps);


                return new double[] {miny,maxy,MidRange,almost};

        }
        public static double MyFunction(double x)
        {
            return (x * x * x + 2) * Math.Cos(4 * x * Math.PI / 180);
        }
        public static void BuildForm(double Xo, double dx ,double Xmax)
            {

                var series = new LineSeries();
                var dots = new ScatterSeries();
                for (double x = Xo; x < Xmax; x += dx)
                {
                    series.Points.Add(new DataPoint(x, MyFunction(x)));
                    dots.Points.Add(new ScatterPoint(x,MyFunction(x)));
                }
                dots.MarkerSize = 2;
                dots.MarkerType = MarkerType.Circle;
            dots.MarkerFill = OxyColors.Red;

                PlotModel model = new PlotModel();
            model.Title = "y(x) = (x^3-2)*cos(4*x)";
                model.Series.Add(series);
                model.Series.Add(dots);
                PlotView plot = new PlotView() { BackColor = Color.White };
                plot.Dock = DockStyle.Fill;
                plot.Model = model;

                var form = new Form() { Width = 600, Height = 500 };

                form.Controls.Add(plot);
                Application.Run(form);
            }




    }
}

