namespace yusupov_lab4
{
    internal class Program
    {
        static void Main(string[] args)
        {
            Console.Title = "Юсупов Е.Э., Вариант 18";
            bool restart;
            do
            {
                try
                {
                    double startX = 0;
                    double endX = 0;
                    double stepX = 0;
                    bool validInput = false;


                    do
                    {
                        Console.WriteLine("Функция: (x^4 + 3)sin(6x)");
                        Console.WriteLine("Введите начальное Х, конечное Х и величину приращения:");
                        string input = Console.ReadLine();
                        string[] parts = input.Split(' ', StringSplitOptions.RemoveEmptyEntries);

                        if (parts.Length != 3)
                        {
                            Console.WriteLine("Ошибка: необходимо ввести 3 числа через пробел");
                            continue;
                        }
                        if (!double.TryParse(parts[0], out startX) || !double.TryParse(parts[1], out endX) || !double.TryParse(parts[2], out stepX))
                        {
                            Console.WriteLine("Ошибка: неверный формат чисел");
                            continue;
                        }
                        if (stepX <= 0)
                        {
                            Console.WriteLine("Ошибка: шаг должен быть больше 0");
                        }
                        else if (startX > endX)
                        {
                            Console.WriteLine("Ошибка: начальное значение не может быть больше конечного");
                        }
                        else
                        {
                            validInput = true;
                        }
                    } while (!validInput);

                    List<double> yValues = new List<double>();
                    double minY = double.MaxValue;
                    double maxY = double.MinValue;
                    double minX = startX;
                    double maxX = startX;
                    double sumY = 0;

                    Console.WriteLine();
                    Console.WriteLine("результаты табулирования");
                    Console.WriteLine(new string('_', 35));
                    Console.WriteLine($"{"№",3} | {"Значение X",10} | {"Значение Y",10}");
                    Console.WriteLine(new string('_', 35));

                    int count = (int)Math.Ceiling((endX - startX) / stepX) + 1;

                    for (int i = 0; i < count; i++)
                    {
                        double x = startX + i * stepX;
                        if (x > endX) x = endX;

                        double y = calculateFunc(x);
                        yValues.Add(y);
                        sumY += y;

                        if (y < minY)
                        {
                            minY = y;
                            minX = x;
                        }
                        if (y > maxY)
                        {
                            maxY = y;
                            maxX = x;
                        }



                        Console.WriteLine($"{i + 1,3} | {x,10:F2} | {y,10:F4}");

                    }
                    Console.WriteLine(new string('_', 35));

                    double average = yValues.Count > 0 ? sumY / yValues.Count : 0;

                    Console.WriteLine();
                    Console.WriteLine("Стаистические характеристики:");
                    Console.WriteLine($"Наименьшее значение: Y = {minY:F4} при X = {minX:F2}");
                    Console.WriteLine($"Наименьшее значение: Y = {maxY:F4} при X = {maxX:F2}");
                    Console.WriteLine($"Среднее арифметическое: {average:F6}");
                    BuildForm();
                    Console.WriteLine();
                    Console.WriteLine("Для повторения работы нажмите Spacebar,");
                }
                catch (Exception ex)
                {
                    Console.WriteLine($"Произошла непредвиденная ошибка: {ex.Message}");

                }
                restart = Console.ReadKey(true).Key == ConsoleKey.Spacebar;

            } while (restart);


        }
        static double calculateFunc(double x)
        {
            return (Math.Pow(x, 4) + 3) * Math.Sin(6 * x);
        }
        public static void BuildForm()
        {

            var series = new LineSeries { Color = OxyColors.Green, Title = "(x^4 + 3)sin(6x)" };


            for (double x = 0; x < 10; x += 0.01)
                series.Points.Add(new DataPoint(x, calculateFunc(x)));


            PlotModel model = new PlotModel();


            model.Series.Add(series);
            var scatterSeries = new ScatterSeries { MarkerType = MarkerType.Circle, MarkerSize = 5, MarkerFill = OxyColors.Red, Title = "Точки табулирования" };
            for (double x = 0; x <= 6.5; x += 0.5)
            {
                scatterSeries.Points.Add(new ScatterPoint(x, calculateFunc(x)));
            }
            model.Series.Add(scatterSeries);


            model.Axes.Add(new LinearAxis { Position = AxisPosition.Bottom, Minimum = 0, Maximum = 6.5 });
            model.Axes.Add(new LinearAxis { Position = AxisPosition.Left});
            model.Legends.Add(new Legend { LegendPlacement = LegendPlacement.Outside, LegendPosition = LegendPosition.TopRight });

            PlotView plot = new PlotView() { BackColor = Color.White };
            plot.Dock = DockStyle.Fill;
            plot.Model = model;

            var form = new Form() { Width = 600, Height = 500 };
            form.Controls.Add(plot);
            System.Windows.Forms.Application.Run(form);
        }
    }
}

