using System;
using System.Collections.Generic;
using System.Linq;
using System.Windows.Forms;
using OxyPlot;
using OxyPlot.Axes;
using OxyPlot.Annotations;
using OxyPlot.Legends;
using OxyPlot.Series;
using OxyPlot.WindowsForms;
using System.Drawing;

namespace ConsoleApp2
{
    internal class Program
    {
        static void Main(string[] args)
        {
            Console.Title = "Шкарбун Д.С., работа №5, Вариант №15";
            Console.WriteLine("Табуляция функции: 4*cos(x/2)*cos(5x/2)*cos(4x)");

            bool repeat = true;

            while (repeat)
            {
                Console.WriteLine("\nВведите три значения через пробел (начальное X, конечное X, приращение dX):");
                string input = Console.ReadLine();

                string[] parts = input.Split(' ', StringSplitOptions.RemoveEmptyEntries);
                if (parts.Length != 3)
                {
                    Console.WriteLine("Ошибка: нужно ввести ровно 3 числа!");
                    continue;
                }

                double startX, endX, stepX;
                if (!double.TryParse(parts[0], out startX) ||
                    !double.TryParse(parts[1], out endX) ||
                    !double.TryParse(parts[2], out stepX))
                {
                    Console.WriteLine("Ошибка: все значения должны быть числами!");
                    continue;
                }

                if (stepX <= 0)
                {
                    Console.WriteLine("Ошибка: шаг должен быть больше 0!");
                    continue;
                }

                if (startX > endX)
                {
                    Console.WriteLine("Ошибка: начальное значение X больше конечного. Невозможно построить таблицу.");
                    continue;
                }

                // Проверка, что первый шаг не выходит за границы
                if (startX + stepX > endX)
                {
                    Console.WriteLine("Ошибка: шаг слишком велик, и в диапазоне [Xнач, Xкон] не будет ни одной точки для вычисления.");
                    continue;
                }

                Console.WriteLine();
                Console.WriteLine("--------------------------------------------------");
                Console.WriteLine("| № | Значение x | Значение y                   |");
                Console.WriteLine("--------------------------------------------------");

                double currentX = startX;
                int index = 1;
                var yValues = new List<double>();
                var xValues = new List<double>();

                while (currentX <= endX)
                {
                    double y = CalculateFunction(currentX);
                    yValues.Add(y);
                    xValues.Add(currentX);

                    Console.WriteLine($"| {index,2} | {currentX,8:F2} | {y,16:F4} |");
                    index++;
                    currentX += stepX;
                }

                Console.WriteLine("--------------------------------------------------");

                if (yValues.Count == 0)
                {
                    Console.WriteLine("Нет значений для расчёта.");
                }
                else
                {
                    double max = yValues.Max();
                    double min = yValues.Min();
                    // Находим индексы для max и min
                    int maxIndex = yValues.IndexOf(max);
                    int minIndex = yValues.IndexOf(min);
                    double maxX = xValues[maxIndex];
                    double minX = xValues[minIndex];

                    double avg = yValues.Average();

                    double sumSquaredDiffs = 0;
                    foreach (double y in yValues)
                    {
                        sumSquaredDiffs += Math.Pow(y - avg, 2);
                    }
                    double variance = sumSquaredDiffs / (yValues.Count - 1);
                    double stdDev = Math.Sqrt(variance);
                    double coefficientOfVariation = (stdDev / avg) * 100;

                    Console.WriteLine($"\nНаибольшее y = {max:F4}, при x = {maxX:F2}");
                    Console.WriteLine($"Наименьшее y = {min:F4}, при x = {minX:F2}");
                    Console.WriteLine($"Среднее = {avg:F2}");
                    Console.WriteLine($"Коэффициент вариации = {coefficientOfVariation:F2}%");
                }

                // Ввод шага для графика
                Console.WriteLine("\nПостроение графиков...");
                double graphStep = 0.01; // значение по умолчанию
                bool validInput = false;

                while (!validInput)
                {
                    Console.Write("Введите шаг для построения графика (например, 0.01): ");
                    string graphStepInput = Console.ReadLine();

                    if (double.TryParse(graphStepInput, out graphStep) && graphStep > 0)
                    {
                        validInput = true;
                    }
                    else
                    {
                        Console.WriteLine("Ошибка: введите положительное число.");
                    }
                }

                Console.WriteLine("\nОткрывается график с двумя линиями: пользовательский шаг (зелёный) и шаг 0.01 (красный). Нажмите любую клавишу для продолжения.");
                Console.ReadKey();

                BuildForm(startX, endX, graphStep);

                Console.WriteLine("\n\nНажмите Spacebar для повтора, любую другую клавишу для выхода.");
                ConsoleKeyInfo key = Console.ReadKey();
                repeat = (key.Key == ConsoleKey.Spacebar);
            }

            Console.WriteLine("\nПрограмма завершена.");
        }

        public static double CalculateFunction(double x)
        {
            return 4 * Math.Cos(x / 2) * Math.Cos(5 * x / 2) * Math.Cos(4 * x);
        }

        public static void BuildForm(double startX, double endX, double customStep)
        {
            var customSeries = new LineSeries
            {
                Title = $"Пользовательский шаг ({customStep})",
                Color = OxyColors.Green,
                StrokeThickness = 2
            };

            var defaultSeries = new LineSeries
            {
                Title = "Шаг 0.01",
                Color = OxyColors.Red,
                StrokeThickness = 2
            };

            for (double x = startX; x <= endX; x += customStep)
            {
                customSeries.Points.Add(new DataPoint(x, CalculateFunction(x)));
            }

            for (double x = startX; x <= endX; x += 0.01)
            {
                defaultSeries.Points.Add(new DataPoint(x, CalculateFunction(x)));
            }

            PlotModel model = new PlotModel();

            model.Title = "y = 4·cos(α/2)·cos(5α/2)·cos(4α)";
            model.TitleColor = OxyColors.Black;
            model.TitleFontSize = 16;

            model.Series.Add(customSeries);
            model.Series.Add(defaultSeries);

            // Оси
            var xAxis = new LinearAxis { Position = AxisPosition.Bottom, Title = "X", Minimum = startX, Maximum = endX };
            var yAxis = new LinearAxis { Position = AxisPosition.Left, Title = "Y" };

            model.Axes.Add(xAxis);
            model.Axes.Add(yAxis);

            // Легенда картинки
            var legend = new Legend
            {
                LegendPosition = LegendPosition.RightTop,
                LegendBackground = OxyColor.FromAColor(200, OxyColors.White),
                LegendBorder = OxyColors.Black
            };
            model.Legends.Add(legend);

            var horizontalLine = new LineAnnotation
            {
                Type = LineAnnotationType.Horizontal,
                Y = 0,
                StrokeThickness = 2,
                Color = OxyColors.Black,
                LineStyle = LineStyle.Solid
            };
            model.Annotations.Add(horizontalLine);

