using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Threading.Tasks;

namespace Five
{
    public class RealArray
    {
        protected double[] arr; // массив чисел
        private int size; // размер массива
        private double range; // диапозон случайных чисел

        public string Description;

        public RealArray()
        {
            size = 10;
            range = 100;
            Description = "Массив по умолчанию";

            FillArray();
        }

        public RealArray(int n, double r)
        {
            size = n;
            range = r;
            Description = $"Массив размером {size} в диапозоне [0, {range}]";
            FillArray();
        }
        public int Size { get { return size; } }
        public double Range { get { return range; } }
        public double[] Arr { get { return arr; } }
        private void FillArray()
        {
            Random rand = new Random();
            arr = new double[size]; // инициализация массива

            for ( int i = 0; i < size; i++)
                arr[i] = (float)Math.Round(rand.NextDouble() * range, 2);
        }

        public string GetArrayString()
        {
            var str = new StringBuilder();
            for (int i = 0; i < arr.Length; i++)
                str.Append(arr[i].ToString("F2") + " ");
            return str.ToString();
        }


    }
    public class ExtendedRealArray : RealArray
    {
        public ExtendedRealArray() : base() { }
        public ExtendedRealArray(int size, double range) : base(size, range) { }


        public double GetAverage()
        {
            double sum = 0;
            for (int i = 0; i < arr.Length; i++)
            {
                sum += arr[i];
            }

            return sum / arr.Length;
        }
        public double FindMin()
        {
            double min = arr[0];
            for (int i = 1; i < arr.Length; i++)
            {
                if (arr[i] < min)
                    min = arr[i];
            }
            return min;
        }

        public double FindMax() 
        {
            double max = arr[0];
            for (int i = 1;i < arr.Length; i++)
            {
                if (arr[i] > max)
                    max = arr[i];
            }
            return max;
        }
        public double GetVariance()
        {
            double average = GetAverage();
            double sum = 0;

            for (int i = 0; i < arr.Length; i++)
            {
                sum += Math.Pow(arr[i] - average, 2);
            }
            double variance = sum / arr.Length;
            return Math.Round(variance,2);
        }

        public double GetMedian()
        {
            double[] sortedArray = (double[])arr.Clone();
            Array.Sort(sortedArray);
            int n = sortedArray.Length;
            if(n % 2 == 0)
                return (sortedArray[n/2 - 1] + sortedArray[n/2]) / 2.0;
            else
                return sortedArray[n/2];
        }

        public string GetFullStatistics()
        {
            return $"Массив: \n{GetArrayString()}\n\n" +
                   $"Статистика: \n" +
                   $"Минимальное значение: {FindMin():F2}\n" +
                   $"Максимальное значение: {FindMax():F2}\n" +
                   $"Дисперсия: {(GetVariance()):F2}\n" +
                   $"Медиана: {GetMedian():F2}\n";
        }
    }
}

