namespace DistanceTest { 
internal class Distance
{
    // Расстояние от точки P(px, py) до отрезка AB с координатами A(ax, ay), B(bx, by)
    static public double GetDistance(double px, double py, double ax, double ay, double bx, double by)
    {

        double distance;

        // Векторы
        double ab_x = bx - ax;
        double ab_y = by - ay;
        double ap_x = px - ax;
        double ap_y = py - ay;

        // Если отрезок вырожден в точку
        if (ab_x == 0 && ab_y == 0)
        {
            distance = Math.Sqrt(ap_x * ap_x + ap_y * ap_y);
            return distance;
        }

        // Параметр проекции и ограничение отрезком [0, 1]
        double t = Math.Max(0, Math.Min(1, (ab_x * ap_x + ab_y * ap_y) / (ab_x * ab_x + ab_y * ab_y)));

        // Ближайшая точка и расстояние
        double closest_x = ax + t * ab_x;
        double closest_y = ay + t * ab_y;
        distance = Math.Sqrt(Math.Pow(px - closest_x, 2) + Math.Pow(py - closest_y, 2));

        return distance;

    }
    //способ ввода - Индексированные метки
