            double b = GetDistance(x2, y2, x3, y3);
            double c = GetDistance(x3, y3, x1, y1);

            double S = (a + b + c) / 2;
            return Math.Sqrt(S * (S - a) * (S - b) * (S - c));
        }

        static double GetArea(double a, double b, double angle)
        {
