        public ArrayProcessor()
        {

            size = 15;
            randMax = 100;
            description = "Объект массива по умолчанию (размер=15, диапазон=100)";
            FillArrayWithRandomNumbers();
        }
        public ArrayProcessor(int n, int r)
        {
            size = n;
            randMax = r;
            description = $"Объект массива (размер={n}, диапазон={r})";
            FillArrayWithRandomNumbers();
        }

        private void FillArrayWithRandomNumbers()
        {
            Random Rand = new Random();
            arr = new int[size];

            for (int i = 0; i < size; i++)
            {
                arr[i] = Rand.Next(randMax);
            }
        }

        public string GetStringArray()
        {

            var str = new StringBuilder();
            for (int i = 0; i < arr.Length; i++)
            {
                str.Append(arr[i] + " ");
            }
            return str.ToString();
        }

        public class ExtendedArray : ArrayProcessor
        {
            public ExtendedArray() : base() { }
            public ExtendedArray(int size, int randMax) : base(size, randMax) { }

            public int GetMinValue()
            {
                int min = arr[0];
                for (int i = 1; i < arr.Length; i++)
                {
                    if (arr[i] < min)
                    {
                        min = arr[i];
                    }
                }
                return min;
            }

            public double GetAverageValue()
            {
                long sum = 0;
                foreach (int num in arr)
                {
                    sum += num;
                }
                return (double)sum / arr.Length;
