                    $"Среднее значение массива: {GetAverageValue()}\n";

            }
        }
    }
}

namespace DistanceTest;
internal class Distance
{
    public static double GetDistance(double px, double py, double ax, double ay, double bx, double by)
    {
        double abX = bx - ax;
        double abY = by - ay;

        double apX = px - ax;
        double apY = py - ay;

        double bpX = px - bx;
        double bpY = py - by;

        double abSquared = abX * abX + abY * abY;

        if (abSquared == 0)
        {
            return D(px, py, ax, ay);
        }

        double dotAP = apX * abX + apY * abY;
        double dotBP = bpX * (-abX) + bpY * (-abY);

        if (dotAP >= 0 && dotBP >= 0)
        {
            return DistanceToLine(px, py, ax, ay, bx, by);
        }
        else
        {
            double distToA = D(px, py, ax, ay);
            double distToB = D(px, py, bx, by);
            return Math.Min(distToA, distToB);
        }
    }

    static double DistanceToLine(double x, double y, double x1, double y1, double x2, double y2)
    {
        //Расстояния до прямой
        double a = y2 - y1;
        double b = x1 - x2;
        double c = x2 * y1 - x1 * y2;

        double chislitel = Math.Abs(a * x + b * y + c);
        double znaminatel = Math.Sqrt(a * a + b * b);

        if (denominator == 0)
        {
            return D(x, y, x1, y1);
        }

        return chislitel / znaminatel;
    }

    // Евклидово расстояние между двумя точками
    static double D(double x1, double y1, double x2, double y2)
    {
        return Math.Sqrt((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1));
    }
}

