using System;
using System.Text;

public class BaseArray
{
    protected double[,] array;
    protected int rows;
    protected int cols;
    public string description;

    public int Rows => rows;
    public int Cols => cols;

    public BaseArray()
    {
        rows = 3;
        cols = 5;
        description = $"объект создан конструктором по умолчанию, строк = {rows}, столбцов = {cols}";
        array = new double[rows, cols];
        FillArrayWithRandom();
    }

    public BaseArray(int rows, int cols)
    {
        this.rows = rows;
        this.cols = cols;
        description = $"объект создан конструктором с параметрами, строк = {rows}, столбцов = {cols}";
        array = new double[rows, cols];
        FillArrayWithRandom();
    }

    protected void FillArrayWithRandom()
    {
        Random rand = new Random();
        for (int i = 0; i < rows; i++)
        {
            for (int j = 0; j < cols; j++)
            {
                array[i, j] = Math.Round(rand.NextDouble() * 100, 2);
            }
        }
    }

    public string GetStringArray()
    {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < rows; i++)
        {
            for (int j = 0; j < cols; j++)
            {
                sb.Append(array[i, j].ToString("0.00") + "\t");
            }
            sb.AppendLine();
        }
        return sb.ToString();
    }
}

// ExtendedArray.cs
public class ExtendedArray : BaseArray
{
    public ExtendedArray() : base() { }
    public ExtendedArray(int rows, int cols) : base(rows, cols) { }

    public double MaxRow(int row)
    {
        if (row < 1 || row > rows)
            throw new ArgumentOutOfRangeException(nameof(row),
                $"Неверный номер строки. Допустимый диапазон: 1-{rows}");

        int zeroBasedRow = row - 1;
        double max = array[zeroBasedRow, 0];
        for (int j = 1; j < cols; j++)
        {
            if (array[zeroBasedRow, j] > max)
                max = array[zeroBasedRow, j];
        }
        return Math.Round(max, 2);
    }

    public double MinRow(int row)
    {
        if (row < 1 || row > rows)
            throw new ArgumentOutOfRangeException(nameof(row),
                $"Неверный номер строки. Допустимый диапазон: 1-{rows}");

        int zeroBasedRow = row - 1;
        double min = array[zeroBasedRow, 0];
        for (int j = 1; j < cols; j++)
        {
            if (array[zeroBasedRow, j] < min)
                min = array[zeroBasedRow, j];
        }
        return Math.Round(min, 2);
    }

    public double AverageRow(int row)
    {
        if (row < 1 || row > rows)
            throw new ArgumentOutOfRangeException(nameof(row),
                $"Неверный номер строки. Допустимый диапазон: 1-{rows}");

        int zeroBasedRow = row - 1;
        double sum = 0;
        for (int j = 0; j < cols; j++)
        {
            sum += array[zeroBasedRow, j];
        }
        return Math.Round(sum / cols, 2);
    }
}

