            string[] numberStrings = Convert.ToString(Console.ReadLine()).Split(" ");
            double.TryParse(numberStrings[0], out p[0]);
            double.TryParse(numberStrings[1], out p[1]);
            double.TryParse(numberStrings[2], out a[0]);
            double.TryParse(numberStrings[3], out a[1]);
            double.TryParse(numberStrings[4], out b[0]);
            double.TryParse(numberStrings[5], out b[1]);



            distance = GetDistance(p[0], p[1], a[0], a[1], b[0], b[1]);


            Console.WriteLine($"Расстояние: {distance}"); ;
            Console.ReadKey();

        }
        static double GetDistance(double px, double py, double ax, double ay, double bx, double by)
        {
            if ((bx - ax) == 0 && (by - ay) == 0) { return Math.Sqrt((px - ax) * (px - ax) + (py - ay) * (py - ay)); }
            double T = (((px - ax) * (bx - ax) + (py - ay) * (by - ay)) / ((bx - ax) * (bx - ax) + (by - ay) * (by - ay)));
            if (T < 0) T = 0;
            else if (T > 1) T = 1;
            double nearX = ax + T * (bx - ax);
            double nearY = ay + T * (by - ay);
            return Math.Sqrt((px - nearX) * (px - nearX) + (py - nearY) * (py - nearY));
        }
    }
}

