namespace DistanceTest
{

    public class Distance
    {
        public static double GetDistance(double px, double py, double ax, double ay, double bx, double by)
        {
            double AB = Math.Pow(bx - ax, 2) + Math.Pow(by - ay, 2);
            if (AB == 0)
            {
                return GetLength(px, ax, py, ay);
            }
            double t = ((px - ax) * (bx - ax) + (py - ay) * (by - ay)) / AB;

            if (t < 0)
            {
                return GetLength(px, ax, py, ay);
            }
            else if (t > 1)
            {
                return GetLength(px, bx, py, by);
            }
            else
            {
                double projX = ax + t * (bx - ax);
                double projY = ay + t * (by - ay);

                return GetLength(px, projX, py, projY);
            }

        }
        static double GetLength(double x1, double y1, double x2, double y2)
        {
            return Math.Sqrt(Math.Pow(x1 - y1, 2) + Math.Pow(x2 - y2, 2));
        }
    }
}

