            double area = GetArea(x1, y1, x2, y2, x3, y3);
            double perimeter = GetPerimeter(x1, y1, x2, y2, x3, y3);

            Console.WriteLine("Площадь треугольника: " + area.ToString("F4") + ("\nПериметр треугольника: " + perimeter.ToString("F4")));

            Console.WriteLine("\nТест 1: Площадь по основанию и высоте");
