            double area1 = GetArea(baseLength, height);
            Console.WriteLine("Площадь треугольника: " + area1);

            Console.WriteLine("\nТест 3: Периметр по трем сторонам");
            Console.Write("Введите сторону a: ");
            double sideA = double.Parse(Console.ReadLine());
            Console.Write("Введите сторону b: ");
            double sideB = double.Parse(Console.ReadLine());
            Console.Write("Введите сторону c: ");
            double sideC = double.Parse(Console.ReadLine());

            double perimeter1 = GetPerimeter(sideA, sideB, sideC);
            Console.WriteLine("Периметр треугольника: " + perimeter1);

            Console.ReadKey();
        }

        // Расстояние между точками
        static double Distance(double x1, double y1, double x2, double y2)
        {
            return Math.Sqrt(Math.Pow(x2 - x1, 2) + Math.Pow(y2 - y1, 2));
        }

        // Площадь по координатам вершин
        static double GetArea(double x1, double y1, double x2, double y2, double x3, double y3)
        {
            double area = 0.5 * Math.Abs((x2 - x1) * (y3 - y1) - (x3 - x1) * (y2 - y1));
            return area;
        }

        // Периметр по координатам вершин
        static double GetPerimeter(double x1, double y1, double x2, double y2, double x3, double y3)
        {
            double a = Distance(x1, y1, x2, y2);
            double b = Distance(x2, y2, x3, y3);
            double c = Distance(x3, y3, x1, y1);
            return a + b + c;
        }

        // Площадь по основанию и высоте
        private static double GetArea(double baseLength, double height)
        {
            return 0.5 * baseLength * height;
        }

        // Периметр по трем сторонам
        private static double GetPerimeter(double sideA, double sideB, double sideC)
        {
            return sideA + sideB + sideC;
        }
    }
}

using System;

class Program
{
    static double GetDistance(double px, double py, double ax, double ay, double bx, double by)
    {
        double ab_x = bx - ax;
        double ab_y = by - ay;

        double ap_x = px - ax;
        double ap_y = py - ay;

        double bp_x = px - bx;
        double bp_y = py - by;

        // Скалярное произведение AB·AP
        double ab_ap = ab_x * ap_x + ab_y * ap_y;

        // Скалярное произведение AB·BP
        double ab_bp = ab_x * bp_x + ab_y * bp_y;

        // Если проекция точки P лежит за точкой A (ближе к A)
        if (ab_ap <= 0)
        {
            // Расстояние от P до A
            return Math.Sqrt(ap_x * ap_x + ap_y * ap_y);
        }

        // Если проекция точки P лежит за точкой B (ближе к B)
        if (ab_bp >= 0)
        {
            // Расстояние от P до B
            return Math.Sqrt(bp_x * bp_x + bp_y * bp_y);
        }

        // Проекция точки P лежит на отрезке AB
        // Вычисляем расстояние как высоту треугольника ABP

        // Длина отрезка AB
        double ab_length = Math.Sqrt(ab_x * ab_x + ab_y * ab_y);

        // Площадь треугольника ABP (через векторное произведение)
        double area = Math.Abs(ab_x * ap_y - ab_y * ap_x);

        // Расстояние = 2 * площадь / основание
        return area / ab_length;
    }

    static double[] ReadPoint(string pointName)
    {
        while (true)
        {
            Console.WriteLine($"Введите координаты точки {pointName} (x y):");
            string input = Console.ReadLine();

            if (string.IsNullOrWhiteSpace(input))
            {
                Console.WriteLine("Ошибка: ввод не может быть пустым. Попробуйте снова.");
                continue;
            }

            string[] coords = input.Split(new char[] { ' ', '\t' }, StringSplitOptions.RemoveEmptyEntries);

            if (coords.Length != 2)
            {
                Console.WriteLine("Ошибка: необходимо ввести два числа через пробел. Попробуйте снова.");
                continue;
            }

            if (double.TryParse(coords[0], out double x) && double.TryParse(coords[1], out double y))
            {
                return new double[] { x, y };
            }
            else
            {
                Console.WriteLine("Ошибка: введены некорректные числа. Попробуйте снова.");
            }
        }
    }

    static void Main()
    {
        // Тестовые данные
        double[][] testData = {
            new double[] {0, 0, 20, 20, 20, 20},
            new double[] {0, 20, -20, 0, 20, 0},
            new double[] {4, 44, 8, 16, 32, 28},
            new double[] {-16, 24, 8, 16, 32, 28},
            new double[] {16, 20, -8, 8, 16, -4},
            new double[] {35, 4, -16, 8, 8, 0}
        };

        Console.WriteLine("Тест | Координаты точек P, A, B | Расстояние");

        // Выполнение тестов
        for (int i = 0; i < testData.Length; i++)
        {
            double[] data = testData[i];
            double distance = GetDistance(data[0], data[1], data[2], data[3], data[4], data[5]);

            Console.WriteLine($"{(i + 1),4} | " +
                            $"{data[0],4:F0} {data[1],4:F0} {data[2],4:F0} {data[3],4:F0} {data[4],4:F0} {data[5],4:F0} | " +
                            $"{distance,10:F4}");
        }

        Console.WriteLine("\nВвод пользовательских данных:");

        double[] p = ReadPoint("P");
        double px = p[0];
        double py = p[1];

        double[] a = ReadPoint("A");
        double ax = a[0];
        double ay = a[1];

        double[] b = ReadPoint("B");
        double bx = b[0];
        double by = b[1];

        double userDistance = GetDistance(px, py, ax, ay, bx, by);
        Console.WriteLine($"\nРезультат:");
        Console.WriteLine($"Точка P: ({px}, {py})");
        Console.WriteLine($"Точка A: ({ax}, {ay})");
        Console.WriteLine($"Точка B: ({bx}, {by})");
        Console.WriteLine($"Расстояние от точки P до отрезка AB: {userDistance:F4}");

        Console.WriteLine("\nНажмите любую клавишу для выхода...");
        Console.ReadKey();
    }
}

using OxyPlot;
using OxyPlot.Series;
using OxyPlot.WindowsForms;
using System;
using System.Collections.Generic;
using System.Globalization;
using System.Windows.Forms;

namespace FunctionTabulation
{
    class Program
    {
        [STAThread] 
        static void Main(string[] args)
        {
            Console.Title = "Зайкова К.Е., работа 4, вариант 3";

            do
            {
                Console.Clear();
                PrintFunctionFormula();
                ProcessTabulation();

                Console.WriteLine("\nНажмите Spacebar для повторения или любую другую клавишу для выхода...");
            } while (Console.ReadKey(true).Key == ConsoleKey.Spacebar);
        }

        static void PrintFunctionFormula()
        {
            Console.WriteLine("Формула функции:");
            Console.WriteLine("sin(2α) + sin(5α) - sin(3α)");
            Console.WriteLine("---------------------------");
            Console.WriteLine("cos(α) + 1 - 2sin²(2α)");
            Console.WriteLine();
        }

        static double CalculateFunction(double alpha)
        {
            double sin2a = Math.Sin(2 * alpha);
            double sin5a = Math.Sin(5 * alpha);
            double sin3a = Math.Sin(3 * alpha);
            double cosa = Math.Cos(alpha);
            double sin2a2 = 2 * Math.Pow(sin2a, 2);

            double numerator = sin2a + sin5a - sin3a;
            double denominator = cosa + 1 - sin2a2;

            if (Math.Abs(denominator) < 1e-10)
                return double.NaN;

            return numerator / denominator;
        }

        static void ProcessTabulation()
        {
            double startX, endX, step;

            if (!ReadInputValues(out startX, out endX, out step))
                return;

            List<double> xValues = new List<double>();
            List<double> yValues = new List<double>();

            Console.WriteLine("\nРезультаты табулирования:");
            Console.WriteLine(new string('-', 50));
            Console.WriteLine("| {0,10} | {1,15} |", "X", "Y");
            Console.WriteLine(new string('-', 50));

            double currentX = startX;
            int index = 0;

            while (currentX <= endX + step / 2)
            {
                double y = CalculateFunction(currentX);
                xValues.Add(currentX);
                yValues.Add(y);

                Console.WriteLine("| {0,10:F2} | {1,15:F4} |",
                    currentX, double.IsNaN(y) ? "не определ." : y.ToString("F4"));

                currentX += step;
                index++;
            }

            Console.WriteLine(new string('-', 50));

            AnalyzeResults(xValues, yValues);

            Console.WriteLine("\nХотите построить график? (y/n)");
            if (Console.ReadKey(true).Key == ConsoleKey.Y)
            {
                PlotGraph(xValues, yValues, startX, endX);
            }
        }

        static bool ReadInputValues(out double startX, out double endX, out double step)
        {
            startX = endX = step = 0;

            while (true)
            {
                Console.WriteLine("Введите начальное значение, конечное значение и шаг (через пробел):");
                string input = Console.ReadLine();

                if (string.IsNullOrWhiteSpace(input))
                {
                    Console.WriteLine("Ошибка: ввод не может быть пустым.");
                    continue;
                }

                string[] parts = input.Split(' ', StringSplitOptions.RemoveEmptyEntries);

                if (parts.Length != 3)
                {
                    Console.WriteLine("Ошибка: необходимо ввести ровно 3 числа.");
                    continue;
                }

                if (!double.TryParse(parts[0], NumberStyles.Any, CultureInfo.InvariantCulture, out startX))
                {
                    Console.WriteLine("Ошибка: неверный формат начального значения.");
                    continue;
                }

                if (!double.TryParse(parts[1], NumberStyles.Any, CultureInfo.InvariantCulture, out endX))
                {
                    Console.WriteLine("Ошибка: неверный формат конечного значения.");
                    continue;
                }

                if (!double.TryParse(parts[2], NumberStyles.Any, CultureInfo.InvariantCulture, out step))
                {
                    Console.WriteLine("Ошибка: неверный формат шага.");
                    continue;
                }

                if (step <= 0)
                {
                    Console.WriteLine("Ошибка: шаг должен быть больше 0.");
                    continue;
                }

                if (startX > endX)
                {
                    Console.WriteLine("Ошибка: начальное значение не может быть больше конечного.");
                    continue;
                }

                break;
            }

            return true;
        }

        static void AnalyzeResults(List<double> xValues, List<double> yValues)
        {
            if (yValues.Count == 0) return;

            double minY = double.MaxValue;
            double maxY = double.MinValue;
            double minX = 0, maxX = 0;
            int validCount = 0;
            double sum = 0, sumSquares = 0;

            for (int i = 0; i < yValues.Count; i++)
            {
                if (!double.IsNaN(yValues[i]) && !double.IsInfinity(yValues[i]))
                {
                    validCount++;
                    sum += yValues[i];
                    sumSquares += yValues[i] * yValues[i];

                    if (yValues[i] < minY)
                    {
                        minY = yValues[i];
                        minX = xValues[i];
                    }

                    if (yValues[i] > maxY)
                    {
                        maxY = yValues[i];
                        maxX = xValues[i];
                    }
                }
            }

            Console.WriteLine("\nАнализ результатов:");
            Console.WriteLine(new string('-', 50));

            if (validCount > 0)
            {
                double mean = sum / validCount;
                double variance = (sumSquares / validCount) - (mean * mean);

                Console.WriteLine($"Наименьшее значение: Y = {minY:F4} при X = {minX:F2}");
                Console.WriteLine($"Наибольшее значение: Y = {maxY:F4} при X = {maxX:F2}");
                Console.WriteLine($"Дисперсия: {variance:F6}");
            }
            else
            {
                Console.WriteLine("Нет допустимых значений функции для анализа.");
            }
        }

        static void PlotGraph(List<double> xValues, List<double> yValues, double startX, double endX)
        {
            try
            {
                var plotModel = new PlotModel
                {
                    Title = $"График функции: f(α) = (sin2α + sin5α - sin3α) / (cosα + 1 - 2sin²2α)\nДиапазон: α ∈ [{startX:F2}, {endX:F2}]"
                };

                var lineSeries = new LineSeries();

                for (int i = 0; i < xValues.Count; i++)
                {
                    if (!double.IsNaN(yValues[i]) && !double.IsInfinity(yValues[i]))
                    {
                        lineSeries.Points.Add(new DataPoint(xValues[i], yValues[i]));
                    }
                }

                plotModel.Series.Add(lineSeries);

                // Создаем и настраиваем форму
                var form = new Form
                {
                    Text = "График функции",
                    Size = new System.Drawing.Size(850, 650),
                    StartPosition = FormStartPosition.CenterScreen
                };

                // Создаем и настраиваем PlotView
                var plotView = new PlotView
                {
                    Model = plotModel,
                    Dock = DockStyle.Fill
                };

                form.Controls.Add(plotView);

                // Запускаем форму
                Application.Run(form);
            }
            catch (Exception ex)
            {
                Console.WriteLine($"Ошибка при построении графика: {ex.Message}");
                Console.WriteLine("Убедитесь, что проект поддерживает Windows Forms.");
            }
        }
    }
}

