            SetStyle(ControlStyles.OptimizedDoubleBuffer |
                    ControlStyles.AllPaintingInWmPaint |
                    ControlStyles.UserPaint, true);
            UpdateStyles();
        }

        private void timer1_Tick(object sender, EventArgs e)
        {
            // Движение первого объекта
            targetPosition.X += dx * speedX;
            targetPosition.Y += dy * speedY;

            // Движение второго объекта
            secondPosition.X += secondSpeedX;
            secondPosition.Y += secondSpeedY;

            // Отскок первого объекта от границ
            if (targetPosition.X <= 0)
            {
                dx = 1; 
                targetPosition.X = 5; 

            }
            else if (targetPosition.X >= ClientSize.Width - targetSize)
            {
                dx = -1; 
                targetPosition.X = ClientSize.Width - targetSize - 5; 

            }

            if (targetPosition.Y <= 0)
            {
                dy = 1; 
                targetPosition.Y = 5;

            }
            else if (targetPosition.Y >= ClientSize.Height - targetSize)
            {
                dy = -1; 
                targetPosition.Y = ClientSize.Height - targetSize - 5;

            }

            // Отскок второго объекта от границ
            if (secondPosition.X <= 0)
            {
                secondSpeedX = Math.Abs(secondSpeedX); // Гарантируем движение вправо
                secondPosition.X = 1;
            }
            else if (secondPosition.X >= ClientSize.Width - secondSize)
            {
                secondSpeedX = -Math.Abs(secondSpeedX); // Гарантируем движение влево
                secondPosition.X = ClientSize.Width - secondSize - 1;
            }

            if (secondPosition.Y <= 0)
            {
                secondSpeedY = Math.Abs(secondSpeedY); 
                secondPosition.Y = 1;
            }
            else if (secondPosition.Y >= ClientSize.Height - secondSize)
            {
                secondSpeedY = -Math.Abs(secondSpeedY); 
                secondPosition.Y = ClientSize.Height - secondSize - 1;
            }

            // Проверка столкновения с курсором
            var cursorPosition = PointToClient(Cursor.Position);
            var cursorRect = new Rectangle(cursorPosition.X - cursorSize / 2,
                                         cursorPosition.Y - cursorSize / 2,
                                         cursorSize, cursorSize);

            var targetRect = new Rectangle(targetPosition.X, targetPosition.Y, targetSize, targetSize);
            var secondRect = new Rectangle(secondPosition.X, secondPosition.Y, secondSize, secondSize);

            if (cursorRect.IntersectsWith(secondRect))
            {
                score++;
                this.Text = "Лови его!";
            }

            // Столкновение с шариком
            if (cursorRect.IntersectsWith(targetRect))
            {
                score++;
                this.Text = "Лови его! - Очки: " + score;

                // Определяем сторону столкновения и отбиваем в противоположную сторону
                float centerX = cursorRect.X + cursorRect.Width / 2;
                float centerY = cursorRect.Y + cursorRect.Height / 2;
                float targetCenterX = targetRect.X + targetRect.Width / 2;
                float targetCenterY = targetRect.Y + targetRect.Height / 2;

                // Отбиваем в сторону от курсора
                if (Math.Abs(targetCenterX - centerX) > Math.Abs(targetCenterY - centerY))
                {
                    // Столкновение по горизонтали
                    dx = (targetCenterX < centerX) ? -1 : 1;
                }
                else
                {
                    // Столкновение по вертикали
                    dy = (targetCenterY < centerY) ? -1 : 1;
                }

                // Добавляем случайную скорость
                speedX = random.Next(8, 20);
                speedY = random.Next(8, 20);

                // Смещаем шар чтобы не застревал
                targetPosition.X += dx * speedX * 2;
                targetPosition.Y += dy * speedY * 2;
            }

            Refresh();
        }

