            var cursorPosition = PointToClient(Cursor.Position);
            var cursorRect = new Rectangle(cursorPosition.X - cursorSize / 2,
                                         cursorPosition.Y - cursorSize / 2,
                                         cursorSize, cursorSize);
            graphics.DrawImage(cursorImage, cursorRect);



            string scoreText = $"Очки: {score}";
            Font scoreFont = new Font("Arial", 16, FontStyle.Bold);
            SizeF textSize = graphics.MeasureString(scoreText, scoreFont);

            // Позиция в правом верхнем углу с отступом 10
            float x = ClientSize.Width - textSize.Width - 10;
            float y = 10;

