namespace Пятый_работ
{
    internal class Tarray
    {

            public Tarray() {Console.WriteLine("Вызван конструктор по умолчанию (строк 4, колонок 2)\n");m_lines = 2;  m_column = 4; ; po = new double[Getlines(), Getcolumn()] ; }
            public Tarray(int lines, int columns) { m_lines = lines; m_column = columns; Console.WriteLine("Вызван конструктор с заданным размером\n"); po = new double[m_lines,m_column]; }
        public void RandArr(int a)
        {
            po = new double[Getlines(), Getcolumn()];
            Console.WriteLine("Вызван метод заполнения рандомными числами\n");
            var joy = new Random();
            int i = 0;
            int j = 0;
            if (a == 1)

            {
                for (i = 0; i < Getcolumn(); i++)
                {
                    for (j = 0; j < Getlines(); j++)
                    {
                        po[j, i] = joy.NextDouble();
                    }
                }
            }
            else
            {
                for (i = 0; i < Getcolumn(); i++)
                {
                    for (j = 0; j < Getlines(); j++)
                    {
                        po[j, i] = joy.NextDouble() * joy.Next(0, a);
                    }
                }
            }
        }
        public string Description() { return "Объект - двухмерный массив с вещественными данными\n"; }
            public int  Getlines() { return m_lines; }
        public void Setlines(int b) { m_lines = b; }
        public int Getcolumn() { return m_column; }
        public void  Setcolumn(int b) { m_column = b ; }
        public double GetMass(int a, int b) { return po[a,b]; }
        public string Writeln()
        {
            string s = "";
            for (int i = 0; i < Getcolumn(); i++)
            {
                for(int j = 0; j < Getlines(); j++)
                {
                    //Console.Write($"{po[j,i],5:F4} ");
                    s += $"{po[j, i],5:F2} ";
                }
                s+= "\n";
            }
            return s;


        }




        private
            int m_lines, m_column;
            double[,] po;
    }
    internal class ExTarray : Tarray
    {
        public ExTarray() : base() { }
        public ExTarray(int a, int b) : base(a, b) { }
        public double MaxInRow(ref int row)
        {

                int i = 0;

            try
            {
                var max = GetMass(0, row);
                while (i < Getlines())
                {
                    if (max < GetMass(i, row))
                    {
                        max = GetMass(i, row);

                    }
                    i++;
                }
                return max;
            }
            catch
            {
            Console.WriteLine("Введите строку из предложенных,а не выдуманных\n");
            row = int.Parse(Console.ReadLine()) - 1;
                return MaxInRow(ref row);
            }
        }
    }
