using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Threading.Tasks;

namespace YusupovLAB_5
{
    public class BaseArray2D
    {
        protected double[,] arr;
        protected int rows;
        protected int cols;
        protected double range;

        public string description;

        public BaseArray2D()
        {
            rows = 4;
            cols = 4;
            range = 100;
            description = "Объект создан конструктором по умолчанию";
            FillArray();
        }
        public BaseArray2D(int r, int c, double rang)
        {
            rows = r;
            cols = c;
            range = rang;
            description = $"Объект создан конструктором с параметрами (сторок={r}, столбцов={c})";
            FillArray();
        }

        void FillArray()
        {
            Random Rand = new Random();
            arr = new double[rows, cols];
            for (int i = 0; i < rows; i++)
                for (int j = 0; j < cols; j++)
                    arr[i, j] = Math.Round(Rand.NextDouble() * range, 2);
        }
        public string GetStringArray()
        {


            var str = new StringBuilder();
            for (int i = 0; i < rows; i++)
            {
                for (int j = 0; j < cols; j++)
                {
                        str.Append($"{arr[i, j], 7:F2} ");
                }

                str.AppendLine();
            }
            return str.ToString();

        }

        public int GetColsCount()
        {
            return cols;
        }
        public int GetRowsCount()
        {
            return rows;
        }
        public double GetRange()
        {
            return range;
        }

    }
    public class ExtendedArray2D : BaseArray2D
    {
        public ExtendedArray2D() : base() { }
        public ExtendedArray2D(int rows, int cols, double range) : base(rows, cols, range) { }

        public double MinCol(int col)
        {
            double min = arr[0, col];
            for (int i = 1; i < rows; i++)
                if (arr[i, col] < min)
                    min = arr[i, col];
            return min;
        }
        public string GetFullStatistics(int col)
        {
            return $"Массив:\n{GetStringArray()}\n" +
            $"Статистика:\n" +
            $"Минимальное значение {col} значение: {MinCol(col -1):F2}\n" +
            $"Описание: {description}";

        }
    }

}

