                scoreBrush = Brushes.Green;
            }
            var rectRect = new Rectangle(rectPosition.X, rectPosition.Y, rectWidth, rectHeight);
            if (cursorRect.IntersectsWith(rectRect))
            {
                score += 5;

                if (score >= 1000)
                {
                    gameWon = true;
                    System.Windows.Forms.Timer restartTimer = new System.Windows.Forms.Timer();

                    restartTimer.Interval = 3000;
                    restartTimer.Tick +=  (s, args) =>
                    {
                        restartTimer.Stop();
                        ResetGame();
                    };
                    restartTimer.Start();
                }
            }

            Refresh();

        }
        public void ResetGame()
        {
            score = 0;
            targetPosition = new Point(500, 500);
            speedX = 10;
            speedY = -10;
            rectPosition = new Point(100, 200);
            scoreBrush = Brushes.Green;
            gameWon = false;
            directionChangeCounter = 0;
            directionChangeInterval = 30;
        }
        private void Form1_MouseClicK(object sender, MouseEventArgs e)
        {
            if (e.Button == MouseButtons.Right)
            {
                ResetGame();
            }
        }
    }
}

using System;
using System.Drawing;
using System.Windows.Forms;

namespace Догони_меня_кирпич
{
    public partial class Form1 : Form
    {
        // --- Поля класса ---

        // Изображения
        private Image targetImage;      // Изображение "человечка" (цель)
        private Image cursorImage;      // Изображение "кирпича" (управляется курсором)

        // Позиции и размеры
        private Point targetPosition;   // Позиция "человечка" (левый верхний угол)
        private int targetSize = 50;    // Размер "человечка"

        private int cursorSize = 50;     // Размер изображения курсора

        // Скорости движения цели
        private int dxTarget;
        private int dyTarget;

        // Позиция и размер второго объекта (плавающего (черного) кирпичика)
        private Point floatingBrickPosition; // Позиция плавающего кирпича
        private int floatingBrickWidth = 60; // Ширина
        private int floatingBrickHeight = 30; // Высота

        // Скорости движения плавающего кирпича
        private int dxFloatingBrick = 2;
        private int dyFloatingBrick = 1;

        // Генератор случайных чисел
        private Random random = new Random();

        // Счётчик попаданий
        private int totalHits = 0;       // Общий счётчик попаданий
        private int requiredHits = 20;   // Сколько попаданий нужно для победы

        // Флаг победы
        private bool gameWon = false;

        // --- Констурктор ---

        public Form1()
        {
            InitializeComponent();

            // Настройки для устранения мерцания
            SetStyle(ControlStyles.OptimizedDoubleBuffer |
                     ControlStyles.AllPaintingInWmPaint |
                     ControlStyles.UserPaint, true);

            // Загрузка изображений
            try
            {
                targetImage = Image.FromFile(@"..\..\images\target.jpg");
                cursorImage = Image.FromFile(@"..\..\images\handler.jpg");
            }
            catch (Exception ex)
            {
                MessageBox.Show($"Ошибка загрузки изображений: {ex.Message}");
                targetImage = new Bitmap(targetSize, targetSize);
                using (Graphics g = Graphics.FromImage(targetImage))
                {
                    g.FillEllipse(Brushes.Red, 0, 0, targetSize, targetSize);
                }

                cursorImage = new Bitmap(cursorSize, cursorSize);
                using (Graphics g = Graphics.FromImage(cursorImage))
                {
                    g.FillRectangle(Brushes.Blue, 0, 0, cursorSize, cursorSize);
                }
            }

            // Инициализация позиций
            InitializeTargetPosition();
            InitializeFloatingBrickPosition();

            // Генерируем случайные начальные скорости для "человечка"
            GenerateRandomTargetSpeed();

            // Устанавливаем курсор мыши в центр формы при старте
            Cursor.Position = PointToScreen(new Point(ClientSize.Width / 2, ClientSize.Height / 2));
        }

        // --- Метод: Инициализировать позицию "человечка" в случайном месте ---
        private void InitializeTargetPosition()
        {
            // Генерируем случайные координаты, чтобы цель не вышла за границы
            int maxX = ClientSize.Width - targetSize;
            int maxY = ClientSize.Height - targetSize;
            targetPosition = new Point(random.Next(0, maxX), random.Next(0, maxY));
        }

        // --- Метод: Инициализировать позицию плавающего (черного)кирпича в случайном месте ---
        private void InitializeFloatingBrickPosition()
        {
            // Генерируем случайные координаты, чтобы кирпич не вышел за границы
            int maxX = ClientSize.Width - floatingBrickWidth;
            int maxY = ClientSize.Height - floatingBrickHeight;
            floatingBrickPosition = new Point(random.Next(0, maxX), random.Next(0, maxY));
        }

        // --- Метод: Генерировать случайную скорость для цели (низкую или высокую) ---
        private void GenerateRandomTargetSpeed()
        {
            int speedRange = random.Next(0, 2) == 0 ? 3 : 6;

            dxTarget = random.Next(-speedRange, speedRange + 1);
            if (dxTarget == 0) dxTarget = 1;

            dyTarget = random.Next(-speedRange, speedRange + 1);
            if (dyTarget == 0) dyTarget = 1;
        }

        // --- Метод: Разрешить коллизию между двумя кирпичиками ---
        private void ResolveCollision(ref Point positionA, int widthA, int heightA, ref Point positionB, int widthB, int heightB)
        {
            Rectangle rectA = new Rectangle(positionA.X, positionA.Y, widthA, heightA);
            Rectangle rectB = new Rectangle(positionB.X, positionB.Y, widthB, heightB);

            if (!rectA.IntersectsWith(rectB))
                return;

            int overlapX = Math.Min(rectA.Right, rectB.Right) - Math.Max(rectA.Left, rectB.Left);
            int overlapY = Math.Min(rectA.Bottom, rectB.Bottom) - Math.Max(rectA.Top, rectB.Top);

            if (overlapX < overlapY)
            {
                if (positionA.X < positionB.X)
                {
                    positionA.X -= overlapX / 2;
                    positionB.X += overlapX / 2;
                }
                else
                {
                    positionA.X += overlapX / 2;
                    positionB.X -= overlapX / 2;
                }
            }
            else
            {
                if (positionA.Y < positionB.Y)
                {
                    positionA.Y -= overlapY / 2;
                    positionB.Y += overlapY / 2;
                }
                else
                {
                    positionA.Y += overlapY / 2;
                    positionB.Y -= overlapY / 2;
                }
            }
        }

        // --- Обработчик для paint ---

        private void Form1_Paint(object sender, PaintEventArgs e)
        {
            var graphics = e.Graphics;

            // --- Рисуем задний фон ---
            try
            {
                Image backgroundImage = Image.FromFile(@"..\..\images\background.jpg");
                graphics.DrawImage(backgroundImage, ClientRectangle);
            }
            catch (Exception ex)
            {
                graphics.Clear(Color.White);
            }

            // --- Рисуем цель (человечка в круге) ---
            // Если игра не закончена, рисуем цель
            if (!gameWon)
            {
                var targetRect = new Rectangle(targetPosition.X, targetPosition.Y, targetSize, targetSize);
                graphics.DrawImage(targetImage, targetRect);
            }

            // --- Рисуем объект, управляемый курсором (кирпич) ---
            Point cursorPosition = PointToClient(Cursor.Position);
            var cursorRect = new Rectangle(
                cursorPosition.X - cursorSize / 2,
                cursorPosition.Y - cursorSize / 2,
                cursorSize,
                cursorSize
            );
            graphics.DrawImage(cursorImage, cursorRect);

            // --- Рисуем плавающий кирпич (черный) ---
            var floatingBrickRect = new Rectangle(floatingBrickPosition.X, floatingBrickPosition.Y, floatingBrickWidth, floatingBrickHeight);
            graphics.FillRectangle(Brushes.Black, floatingBrickRect);
            graphics.DrawRectangle(Pens.White, floatingBrickRect);

            // --- Рисуем счётчик попаданий ---
            string scoreText = $"Попаданий: {totalHits} / {requiredHits}";
            Font font = new Font("Arial", 12, FontStyle.Bold);
            SizeF textSize = graphics.MeasureString(scoreText, font);
            PointF textPosition = new PointF(10, 10); // В левом верхнем углу
            graphics.DrawString(scoreText, font, Brushes.Black, textPosition);
        }

        // --- Обработчик для timer1_tick ---

        private void timer1_Tick(object sender, EventArgs e)
        {
            // Если игра закончена, не двигаемся
            if (gameWon)
                return;

            // Обновляем позицию "человечка"
            targetPosition.X += dxTarget;
            targetPosition.Y += dyTarget;

            // Обновляем позицию плавающего (черного) кирпичика
            floatingBrickPosition.X += dxFloatingBrick;
            floatingBrickPosition.Y += dyFloatingBrick;

            // --- Проверка коллизии с краями оконного приложения ---

            // Коллизия для цели (человечка)
            if (targetPosition.X <= 0 || targetPosition.X + targetSize >= ClientSize.Width)
            {
                dxTarget = -dxTarget;
            }
            if (targetPosition.Y <= 0 || targetPosition.Y + targetSize >= ClientSize.Height)
            {
                dyTarget = -dyTarget;
            }

            // Коллизия для плавающего (черного) кирпичика
            if (floatingBrickPosition.X <= 0 || floatingBrickPosition.X + floatingBrickWidth >= ClientSize.Width)
            {
                dxFloatingBrick = -dxFloatingBrick;
                // Принудительно ставим на границу, чтобы не вылетал
                if (floatingBrickPosition.X <= 0)
                    floatingBrickPosition.X = 0;
                else
                    floatingBrickPosition.X = ClientSize.Width - floatingBrickWidth;
            }
            if (floatingBrickPosition.Y <= 0 || floatingBrickPosition.Y + floatingBrickHeight >= ClientSize.Height)
            {
                dyFloatingBrick = -dyFloatingBrick;
                // Принудительно ставим на границу, чтобы не вылетал
                if (floatingBrickPosition.Y <= 0)
                    floatingBrickPosition.Y = 0;
                else
                    floatingBrickPosition.Y = ClientSize.Height - floatingBrickHeight;
            }

            // --- Проверка коллизии "человечка" с черным кирпичиком ---
            Rectangle targetBounds = new Rectangle(targetPosition.X, targetPosition.Y, targetSize, targetSize);
            Rectangle floatingBrickBounds = new Rectangle(floatingBrickPosition.X, floatingBrickPosition.Y, floatingBrickWidth, floatingBrickHeight);

            if (targetBounds.IntersectsWith(floatingBrickBounds))
            {
                // Цель столкнулась с плавающим кирпичом — отталкиваем их
                dxTarget = -dxTarget;
                dyTarget = -dyTarget;
                dxFloatingBrick = -dxFloatingBrick;
                dyFloatingBrick = -dyFloatingBrick;

                // Выталкиваем объекты, чтобы они не застревали
                ResolveCollision(ref targetPosition, targetSize, targetSize, ref floatingBrickPosition, floatingBrickWidth, floatingBrickHeight);
            }

            // --- Проверка коллизии с курсором (Черного кирпичика) ---
            Point cursorPosition = PointToClient(Cursor.Position);
            Rectangle cursorBounds = new Rectangle(
                cursorPosition.X - cursorSize / 2,
                cursorPosition.Y - cursorSize / 2,
                cursorSize,
                cursorSize
            );

            if (floatingBrickBounds.IntersectsWith(cursorBounds))
            {
                dxFloatingBrick = (int)(-dxFloatingBrick * 1f);
                dyFloatingBrick = (int)(-dyFloatingBrick * 1f);

                // Выталкиваем кирпичик (черный) в сторону от курсора
                int overlapX = Math.Min(floatingBrickBounds.Right, cursorBounds.Right) - Math.Max(floatingBrickBounds.Left, cursorBounds.Left);
                int overlapY = Math.Min(floatingBrickBounds.Bottom, cursorBounds.Bottom) - Math.Max(floatingBrickBounds.Top, cursorBounds.Top);

                if (overlapX < overlapY)
                {
                    if (floatingBrickPosition.X < cursorPosition.X - cursorSize / 2)
                        floatingBrickPosition.X -= overlapX;
                    else
                        floatingBrickPosition.X += overlapX;
                }
                else
                {
                    if (floatingBrickPosition.Y < cursorPosition.Y - cursorSize / 2)
                        floatingBrickPosition.Y -= overlapY;
                    else
                        floatingBrickPosition.Y += overlapY;
                }

                // Принудительно ограничиваем позицию для черного кирпичика, чтобы не вылетел за границы
                if (floatingBrickPosition.X < 0) floatingBrickPosition.X = 0;
                if (floatingBrickPosition.X + floatingBrickWidth > ClientSize.Width) floatingBrickPosition.X = ClientSize.Width - floatingBrickWidth;
                if (floatingBrickPosition.Y < 0) floatingBrickPosition.Y = 0;
                if (floatingBrickPosition.Y + floatingBrickHeight > ClientSize.Height) floatingBrickPosition.Y = ClientSize.Height - floatingBrickHeight;
            }

            // --- Проверка попадания ("Кирпичик" догнал "человечка") ---

            // Проверяем, пересекаются ли прямоугольники
            if (targetBounds.IntersectsWith(cursorBounds))
            {
                // Попадание!
                totalHits++;

                if (totalHits >= requiredHits)
                {
                    // Останавливаем таймер
                    timer1.Stop();
                    DialogResult result = MessageBox.Show($"Поздравляем! Вы победили, сделав {requiredHits} попаданий!", "Победа!", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    if (result == DialogResult.OK)
                    {
                        gameWon = false;
                        totalHits = 0;
                        InitializeTargetPosition();
                        InitializeFloatingBrickPosition();
                        GenerateRandomTargetSpeed();
                        dxFloatingBrick = 2;
                        dyFloatingBrick = 1;
                        timer1.Start();
                    }
                }
                else
                {
                    InitializeTargetPosition();
                    GenerateRandomTargetSpeed();
                }
            }

            Refresh();
        }

        // --- Обработчик для form load ---

        private void Form1_Load(object sender, EventArgs e)
        {
            // Запускаем таймер при загрузке формы
            timer1.Start();
        }
    }
}

using System;
using System.Drawing;
using System.Windows.Forms;

namespace LAB_6
{
    public partial class Form1 : Form
    {
        // поля для первого объекта (шар)
        Image targetImage;
        Point targetPosition = new Point(300, 300);
        int targetSize = 50;
        int dx1 = 1;
        int dy1 = 1;
        int speedX1 = 5;
        int speedY1 = 5;

        // поля для второго объекта (прямоугольник)
        Rectangle rectPosition = new Rectangle(100, 100, 80, 60);
        int dx2 = 1;
        int dy2 = 1;
        int speedX2 = 7;
        int speedY2 = 4;

        // поля для курсора
        Image cursorImage;
        int cursorSize = 50;

        // счетчик очков
        int score = 0;
        Random random = new Random();

        // шрифт для отображения счета
        Font scoreFont = new Font("Arial", 16, FontStyle.Bold);

        // таймер
        private System.Windows.Forms.Timer timer1 = new System.Windows.Forms.Timer();

        public Form1()
        {
            InitializeComponent();

            try
            {
                targetImage = Image.FromFile("D:\\лабы\\LAB_6\\LAB_6\\images\\target.jpg");
                cursorImage = Image.FromFile("D:\\лабы\\LAB_6\\LAB_6\\images\\kurs.png");
                this.BackgroundImage = Image.FromFile("D:\\лабы\\LAB_6\\LAB_6\\images\\background.jpg");
            }
            catch (Exception ex)
            {
                MessageBox.Show($"Ошибка загрузки изображений: {ex.Message}");
                // Создаем простые изображения программно, если файлы не найдены
                targetImage = CreateSampleImage(50, 50, Color.Red);
                cursorImage = CreateSampleImage(50, 50, Color.Green);
                this.BackgroundImage = CreateSampleImage(800, 600, Color.LightBlue);
            }

            this.Text = "Catch It!";

            // настройка фонового изображения
            this.BackgroundImageLayout = ImageLayout.Stretch;

            // настройки рисования для исключения мерцания
            SetStyle(ControlStyles.OptimizedDoubleBuffer |
                    ControlStyles.AllPaintingInWmPaint |
                    ControlStyles.UserPaint, true);
            UpdateStyles();

            // настройка таймера
            timer1.Interval = 25;
            timer1.Tick += new EventHandler(timer1_Tick);
            timer1.Enabled = true;
        }

        // метод для создания простого изображения, если файлы не найдены
        private Bitmap CreateSampleImage(int width, int height, Color color)
        {
            Bitmap bmp = new Bitmap(width, height);
            using (Graphics g = Graphics.FromImage(bmp))
            {
                using (SolidBrush brush = new SolidBrush(color))
                {
                    g.FillRectangle(brush, 0, 0, width, height);
                }
            }
            return bmp;
        }

        private void Form1_Paint(object sender, PaintEventArgs e)
        {
            var graphics = e.Graphics;

            // рисуем первый объект (шар)
            var targetRect = new Rectangle(targetPosition.X, targetPosition.Y, targetSize, targetSize);
            graphics.DrawImage(targetImage, targetRect);

            // рисуем второй объект (прямоугольник) с помощью FillRectangle
            SolidBrush blueBrush = new SolidBrush(Color.Blue);
            graphics.FillRectangle(blueBrush, rectPosition);

            // также рисуем контур прямоугольника с помощью DrawRectangle
            Pen blackPen = new Pen(Color.Black, 2);
            graphics.DrawRectangle(blackPen, rectPosition);

            // рисуем объект-курсор
            if (cursorImage != null)
            {
                Point cursorPoint = new Point(
                    Cursor.Position.X - this.Location.X - cursorSize / 2,
                    Cursor.Position.Y - this.Location.Y - cursorSize / 2 - 30
                );
                var cursorRect = new Rectangle(cursorPoint.X, cursorPoint.Y, cursorSize, cursorSize);
                graphics.DrawImage(cursorImage, cursorRect);

                // проверка столкновение курсора с шаром
                if (cursorRect.IntersectsWith(targetRect))
                {
                    score++;
                    // изменяем направление шара при столкновении
                    dx1 = -dx1;
                    dy1 = -dy1;
                    // перемещаем шар в случайное место
                    targetPosition.X = random.Next(50, Math.Max(51, this.ClientSize.Width - targetSize - 50));
                    targetPosition.Y = random.Next(50, Math.Max(51, this.ClientSize.Height - targetSize - 50));
                    // случайное изменение скорости
                    speedX1 = random.Next(3, 12);
                    speedY1 = random.Next(3, 12);
                }
            }

            // отображаем счет 
            SolidBrush textBrush = new SolidBrush(Color.White);
            graphics.DrawString($"Очки: {score}", scoreFont, textBrush, 10, 10);
        }

        private void timer1_Tick(object sender, EventArgs e)
        {
            // движение первого объекта (шар)
            targetPosition.X += dx1 * speedX1;
            targetPosition.Y += dy1 * speedY1;

            // движение второго объекта (прямоугольник)
            rectPosition.X += dx2 * speedX2;
            rectPosition.Y += dy2 * speedY2;

            // проверка столкновения с границами для шара
            if (targetPosition.X <= 0 || targetPosition.X >= this.ClientSize.Width - targetSize)
            {
                dx1 = -dx1;
                speedX1 = random.Next(3, 12); // случайное изменение скорости
            }
            if (targetPosition.Y <= 0 || targetPosition.Y >= this.ClientSize.Height - targetSize)
            {
                dy1 = -dy1;
                speedY1 = random.Next(3, 12); // случайное изменение скорости
            }

            // проверка столкновения с границами для прямоугольника
            if (rectPosition.X <= 0 || rectPosition.X >= this.ClientSize.Width - rectPosition.Width)
            {
                dx2 = -dx2;
                speedX2 = random.Next(4, 10); // случайное изменение скорости
            }
            if (rectPosition.Y <= 0 || rectPosition.Y >= this.ClientSize.Height - rectPosition.Height)
            {
                dy2 = -dy2;
                speedY2 = random.Next(4, 10); // случайное изменение скорости
            }

            Refresh();
        }

        private void Form1_Load(object sender, EventArgs e)
        {
            this.DoubleBuffered = true;
        }

        private void Form1_Resize(object sender, EventArgs e)
        {
            // корректировка позиций объектов при изменении размера формы
            if (targetPosition.X > this.ClientSize.Width - targetSize)
                targetPosition.X = Math.Max(0, this.ClientSize.Width - targetSize);
            if (targetPosition.Y > this.ClientSize.Height - targetSize)
                targetPosition.Y = Math.Max(0, this.ClientSize.Height - targetSize);
            if (rectPosition.X > this.ClientSize.Width - rectPosition.Width)
                rectPosition.X = Math.Max(0, this.ClientSize.Width - rectPosition.Width);
            if (rectPosition.Y > this.ClientSize.Height - rectPosition.Height)
                rectPosition.Y = Math.Max(0, this.ClientSize.Height - rectPosition.Height);
        }
    }
}

using System;

namespace ConsoleLab5
{
    // Базовый класс
    public class BaseArray
    {
        protected int[] array; // защищенное поле
        private int size;
        private int range;

        // Открытое поле
        public string description;

        // Конструктор по умолчанию без параметров
        public BaseArray()
        {
            this.size = 5;
            this.range = 100;
            this.array = new int[size];
            this.description = "Базовый массив по умолчанию";
            FillArray();
        }

        // Перегруженный конструктор с двумя параметрами
        public BaseArray(int size, int range)
        {
            if (size <= 0 || range <= 0)
                throw new ArgumentException("Размер и диапазон должны быть положительными числами");

            this.size = size;
            this.range = range;
            this.array = new int[size];
            this.description = $"Базовый массив {size} элементов";
            FillArray();
        }

        // Закрытый метод заполнения массива случайными числами
        private void FillArray()
        {
            Random rand = new Random();
            for (int i = 0; i < size; i++)
                array[i] = rand.Next(range);
        }

        // Метод возвращает строку чисел массива
        public string GetStringArray()
        {
            return string.Join(" ", array);
        }

        // Защищенный метод для получения размера
        protected int GetSize()
        {
            return size;
        }

        // Защищенный метод для получения диапазона
        protected int GetRange()
        {
            return range;
        }
    }

    // Производный класс наследует базовый, добавляет методы
    public class ExtendedArray : BaseArray
    {
        // Конструкторы вызывают базовые конструкторы
        public ExtendedArray() : base()
        {
            description = "Расширенный массив по умолчанию";
        }

        public ExtendedArray(int size, int range) : base(size, range)
        {
            description = $"Размер массива: {size} элементов";
        }

        // Возвращает наибольший элемент массива
        public int FindMax()
        {
            if (array == null || array.Length == 0)
                throw new InvalidOperationException("Массив пуст");

            int max = array[0];
            for (int i = 1; i < array.Length; i++)
            {
                if (array[i] > max)
                    max = array[i];
            }
            return max;
        }

        // Возвращает наименьший элемент массива
        public int FindMin()
        {
            if (array == null || array.Length == 0)
                throw new InvalidOperationException("Массив пуст");

            int min = array[0];
            for (int i = 1; i < array.Length; i++)
            {
                if (array[i] < min)
                    min = array[i];
            }
            return min;
        }

        // Поиск медианы
        public double GetMedian()
        {
            if (array == null || array.Length == 0)
                throw new InvalidOperationException("Массив пуст");

            // Создаем копию для сортировки
            int[] sortedArray = new int[array.Length];
            Array.Copy(array, sortedArray, array.Length);
            Array.Sort(sortedArray);

            int middle = sortedArray.Length / 2;

            if (sortedArray.Length % 2 == 0)
            {
                return (sortedArray[middle - 1] + sortedArray[middle]) / 2.0;
            }
            else
            {
                return sortedArray[middle];
            }
        }

        // Вычисление среднего арифметического
        public double GetAverage()
        {
            if (array == null || array.Length == 0)
                throw new InvalidOperationException("Массив пуст");

            double sum = 0;
            foreach (int num in array)
                sum += num;

            return sum / array.Length;
        }

        // Статистика массива
        public string GetFullStatistics()
        {

return $"{description}\n" +
                   $"Массив: {GetStringArray()}\n" +
                   $"Статистика:\n" +
                   $"• Минимальное значение: {FindMin()}\n" +
                   $"• Максимальное значение: {FindMax()}\n" +
                   $"• Медиана: {GetMedian():F2}\n";
        }
    }

